File uploads are a common attack vector for path traversal attacks. Attackers manipulate filenames to write files outside your intended upload directory, potentially overwriting critical system files or placing malicious scripts in web-accessible locations.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');

const app = express();

// VULNERABLE: Uses user-supplied filename directly
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    cb(null, 'uploads/');
  },
  filename: function (req, file, cb) {
    // DANGEROUS: Trusts user-supplied filename
    cb(null, file.originalname);
  }
});

const upload = multer({ storage: storage });

app.post('/api/upload', upload.single('avatar'), (req, res) => {
  // VULNERABLE: No path validation
  const userPath = req.body.subfolder || '';
  const finalPath = path.join('uploads', userPath, req.file.filename);

  // Moves file to user-specified location without validation
  fs.renameSync(req.file.path, finalPath);

  res.json({ message: 'File uploaded', path: finalPath });
});

app.listen(3000);
```

**Attack Payload**:
```text
POST /api/upload HTTP/1.1
Content-Type: multipart/form-data; boundary=----WebKitFormBoundary

------WebKitFormBoundary
Content-Disposition: form-data; name="subfolder"

../../../etc/cron.d
------WebKitFormBoundary
Content-Disposition: form-data; name="avatar"; filename="../../../var/www/html/shell.php"
Content-Type: image/png

<?php system($_GET['cmd']); ?>
------WebKitFormBoundary--
```

**Why This Is Dangerous**:
- Attacker can use `../` sequences in filename to escape upload directory
- User-controlled `subfolder` parameter allows arbitrary path specification
- No validation that final path remains within intended directory
- Can overwrite system files like `/etc/cron.d/*` for persistent access
- Can place PHP/JS files in web root for remote code execution

**SECURE VERSION**:

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');
const fs = require('fs').promises;

const app = express();

// Define absolute upload directory
const UPLOAD_DIR = path.resolve(__dirname, 'uploads');
const ALLOWED_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.gif', '.webp'];
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

// SECURE: Generate random filename, ignore user input
const storage = multer.diskStorage({
  destination: function (req, file, cb) {
    cb(null, UPLOAD_DIR);
  },
  filename: function (req, file, cb) {
    // Generate cryptographically random filename
    const randomName = crypto.randomBytes(32).toString('hex');
    const ext = path.extname(file.originalname).toLowerCase();
    cb(null, `${randomName}${ext}`);
  }
});

// SECURE: Validate file type and size
const fileFilter = (req, file, cb) => {
  const ext = path.extname(file.originalname).toLowerCase();

  if (!ALLOWED_EXTENSIONS.includes(ext)) {
    return cb(new Error('Invalid file type'), false);
  }

  // Validate MIME type matches extension
  const mimeTypes = {
    '.jpg': 'image/jpeg',
    '.jpeg': 'image/jpeg',
    '.png': 'image/png',
    '.gif': 'image/gif',
    '.webp': 'image/webp'
  };

  if (file.mimetype !== mimeTypes[ext]) {
    return cb(new Error('MIME type mismatch'), false);
  }

  cb(null, true);
};

const upload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: { fileSize: MAX_FILE_SIZE }
});

// SECURE: Validate path stays within upload directory
function isPathWithinDirectory(filePath, directory) {
  const resolvedPath = path.resolve(filePath);
  const resolvedDir = path.resolve(directory);
  return resolvedPath.startsWith(resolvedDir + path.sep);
}

app.post('/api/upload', upload.single('avatar'), async (req, res) => {
  try {
    if (!req.file) {
      return res.status(400).json({ error: 'No file uploaded' });
    }

    const finalPath = path.join(UPLOAD_DIR, req.file.filename);

    // CRITICAL: Verify path is within upload directory
    if (!isPathWithinDirectory(finalPath, UPLOAD_DIR)) {
      await fs.unlink(req.file.path);
      return res.status(400).json({ error: 'Invalid file path' });
    }

    res.json({ 
      message: 'File uploaded successfully',
      filename: req.file.filename
    });
  } catch (error) {
    console.error('Upload error:', error.message);
    res.status(500).json({ error: 'Upload failed' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Random filename generation**: User-supplied filename is completely ignored, replaced with cryptographically random string
- **Path canonicalization check**: `isPathWithinDirectory()` uses `path.resolve()` to resolve all `../` sequences and verify the final path stays within the upload directory
- **Extension whitelist**: Only specific, safe image extensions are allowed
- **MIME type validation**: Verifies Content-Type header matches the file extension to prevent disguised uploads
- **File size limits**: Prevents denial of service through large file uploads

Creating user-specific subdirectories is common but requires careful handling to prevent directory traversal. The key is to never trust user input for path construction and always validate the final resolved path.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');
const fs = require('fs').promises;
const sharp = require('sharp'); // For image validation
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

// Configuration
const config = {
  uploadDir: path.resolve(__dirname, 'uploads'),
  allowedExtensions: ['.jpg', '.jpeg', '.png', '.gif', '.webp'],
  maxFileSize: 5 * 1024 * 1024,
  maxFilesPerUser: 50
};

// Rate limiting for uploads
const uploadLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 20, // 20 uploads per window
  message: { error: 'Too many uploads, try again later' }
});

// Audit logger
const auditLog = async (event, details) => {
  const logEntry = {
    timestamp: new Date().toISOString(),
    event,
    ...details
  };
  console.log('[AUDIT]', JSON.stringify(logEntry));
  // In production: send to SIEM/logging service
};

// SECURE: Generate user directory from authenticated user ID
function getUserDirectory(userId) {
  // Hash user ID to prevent enumeration and path manipulation
  const hashedId = crypto
    .createHash('sha256')
    .update(String(userId))
    .digest('hex')
    .substring(0, 16);

  return path.join(config.uploadDir, hashedId);
}

// SECURE: Comprehensive path validation
function validatePath(targetPath, baseDirectory) {
  const resolved = path.resolve(targetPath);
  const base = path.resolve(baseDirectory);

  // Must start with base directory
  if (!resolved.startsWith(base + path.sep) && resolved !== base) {
    return { valid: false, reason: 'Path escapes base directory' };
  }

  // Check for null bytes (can bypass some checks)
  if (targetPath.includes('\0')) {
    return { valid: false, reason: 'Null byte in path' };
  }

  // Check for suspicious patterns
  const suspicious = ['..', '~', '$', '`', '|', ';', '&'];
  for (const pattern of suspicious) {
    if (targetPath.includes(pattern)) {
      return { valid: false, reason: `Suspicious pattern: ${pattern}` };
    }
  }

  return { valid: true, resolvedPath: resolved };
}

// SECURE: Validate actual image content
async function validateImageContent(filePath) {
  try {
    const metadata = await sharp(filePath).metadata();
    const validFormats = ['jpeg', 'png', 'gif', 'webp'];

    if (!validFormats.includes(metadata.format)) {
      return { valid: false, reason: 'Invalid image format' };
    }

    // Check for reasonable dimensions (anti-DoS)
    if (metadata.width > 10000 || metadata.height > 10000) {
      return { valid: false, reason: 'Image dimensions too large' };
    }

    return { valid: true, metadata };
  } catch (error) {
    return { valid: false, reason: 'Failed to parse as image' };
  }
}

// Multer configuration with secure storage
const storage = multer.diskStorage({
  destination: async function (req, file, cb) {
    try {
      // Get user ID from authenticated session (never from request body)
      const userId = req.user?.id;
      if (!userId) {
        return cb(new Error('Authentication required'));
      }

      const userDir = getUserDirectory(userId);

      // Validate the directory path
      const validation = validatePath(userDir, config.uploadDir);
      if (!validation.valid) {
        await auditLog('PATH_TRAVERSAL_ATTEMPT', {
          userId,
          attemptedPath: userDir,
          reason: validation.reason,
          ip: req.ip
        });
        return cb(new Error('Invalid upload path'));
      }

      // Create directory if it doesn't exist
      await fs.mkdir(validation.resolvedPath, { recursive: true });

      cb(null, validation.resolvedPath);
    } catch (error) {
      cb(error);
    }
  },
  filename: function (req, file, cb) {
    // Generate cryptographically secure random filename
    const randomName = crypto.randomBytes(32).toString('hex');
    const timestamp = Date.now();
    const ext = path.extname(file.originalname).toLowerCase();

    // Validate extension before using
    if (!config.allowedExtensions.includes(ext)) {
      return cb(new Error('Invalid file extension'));
    }

    cb(null, `${timestamp}-${randomName}${ext}`);
  }
});

const upload = multer({
  storage,
  limits: {
    fileSize: config.maxFileSize,
    files: 1
  },
  fileFilter: (req, file, cb) => {
    const ext = path.extname(file.originalname).toLowerCase();

    if (!config.allowedExtensions.includes(ext)) {
      return cb(new multer.MulterError('LIMIT_UNEXPECTED_FILE', 'Invalid file type'));
    }

    cb(null, true);
  }
});

// Authentication middleware (example)
const authenticate = (req, res, next) => {
  // In production: validate JWT/session
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Decode and verify token (simplified)
  try {
    // In production: jwt.verify(token, secret)
    req.user = { id: 12345 }; // Extracted from verified token
    next();
  } catch (error) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// Upload endpoint with full security controls
app.post('/api/upload',
  authenticate,
  uploadLimiter,
  upload.single('avatar'),
  async (req, res) => {
    const startTime = Date.now();

    try {
      if (!req.file) {
        return res.status(400).json({ error: 'No file uploaded' });
      }

      const filePath = req.file.path;

      // DEFENSE IN DEPTH: Validate image content after upload
      const imageValidation = await validateImageContent(filePath);
      if (!imageValidation.valid) {
        // Delete invalid file immediately
        await fs.unlink(filePath).catch(() => {});

        await auditLog('INVALID_FILE_CONTENT', {
          userId: req.user.id,
          originalName: req.file.originalname,
          reason: imageValidation.reason,
          ip: req.ip
        });

        return res.status(400).json({ error: 'Invalid image file' });
      }

      // Strip EXIF data for privacy and security
      const cleanedPath = filePath.replace(/\.[^.]+$/, '_clean$&');
      await sharp(filePath)
        .rotate() // Auto-rotate based on EXIF
        .toFile(cleanedPath);

      // Replace original with cleaned version
      await fs.unlink(filePath);
      await fs.rename(cleanedPath, filePath);

      // Log successful upload
      await auditLog('FILE_UPLOADED', {
        userId: req.user.id,
        filename: req.file.filename,
        size: req.file.size,
        format: imageValidation.metadata.format,
        processingTime: Date.now() - startTime,
        ip: req.ip
      });

      res.json({
        success: true,
        filename: req.file.filename,
        size: req.file.size
      });

    } catch (error) {
      console.error('Upload processing error:', error);

      // Clean up on error
      if (req.file?.path) {
        await fs.unlink(req.file.path).catch(() => {});
      }

      res.status(500).json({ error: 'Upload processing failed' });
    }
  }
);

// Error handler for multer
app.use((error, req, res, next) => {
  if (error instanceof multer.MulterError) {
    if (error.code === 'LIMIT_FILE_SIZE') {
      return res.status(400).json({ error: 'File too large' });
    }
    return res.status(400).json({ error: 'Upload error' });
  }
  next(error);
});

app.listen(3000, () => {
  console.log('Server running with secure file uploads');
});
```

**Defense in Depth Layers**:

1. **Authentication-based directory assignment**:
```javascript
// User ID comes from verified token, not request body
const userId = req.user?.id; // From JWT verification
const userDir = getUserDirectory(userId); // Hashed to prevent enumeration
```

2. **Multi-layer path validation**:
```javascript
// Check canonical path, null bytes, and suspicious patterns
function validatePath(targetPath, baseDirectory) {
  const resolved = path.resolve(targetPath);
  if (!resolved.startsWith(base + path.sep)) return { valid: false };
  if (targetPath.includes('\0')) return { valid: false };
  // Additional pattern checks...
}
```

3. **Content validation beyond MIME type**:
```javascript
// Actually parse the image to verify it's valid
const metadata = await sharp(filePath).metadata();
if (!validFormats.includes(metadata.format)) {
  // Delete and reject
}
```

**Additional Protections**:
- **EXIF stripping**: Removes potentially malicious metadata and protects user privacy
- **Rate limiting**: Prevents abuse and DoS via excessive uploads (20 per 15 minutes)
- **Comprehensive audit logging**: All upload attempts logged with user ID, IP, and file details for forensic analysis
- **Hashed user directories**: User IDs are hashed to prevent directory enumeration attacks
- **Immediate cleanup on validation failure**: Invalid files are deleted before response to prevent accumulation of malicious files
- **Dimension limits**: Prevents decompression bomb attacks where small files expand to massive images

File uploads are a critical attack surface. The biggest risk is path traversal, where attackers manipulate filenames to write files outside your intended directory. This was exploited in CVE-2023-50164 (Apache Struts) affecting enterprise applications worldwide.

**VULNERABLE CODE**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

@RestController
@RequestMapping("/api/profile")
public class ProfileController {

    private static final String UPLOAD_DIR = "/var/www/uploads/profiles/";

    @PostMapping("/upload")
    public String uploadProfilePicture(@RequestParam("file") MultipartFile file) 
            throws IOException {

        // VULNERABLE: Using original filename directly from user input
        String filename = file.getOriginalFilename();

        // VULNERABLE: No path validation - attacker can use ../../../etc/cron.d/backdoor
        Path targetPath = Paths.get(UPLOAD_DIR + filename);

        // File is written to attacker-controlled location
        Files.write(targetPath, file.getBytes());

        return "File uploaded: " + filename;
    }
}
```

**Attack Payload**:
```text
Filename: ../../../var/www/html/shell.jsp
Content: <%Runtime.getRuntime().exec(request.getParameter("cmd"));%>
```

**Why This Is Dangerous**:
- Attacker controls the filename via `getOriginalFilename()` which comes directly from HTTP request
- Path like `../../../etc/cron.d/malicious` escapes upload directory and writes to system locations
- No content-type validation allows uploading executable files (JSP, PHP, etc.)
- Attackers can overwrite web application files to achieve remote code execution

**SECURE VERSION**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.Set;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@RestController
@RequestMapping("/api/profile")
public class SecureProfileController {

    private static final Logger logger = LoggerFactory.getLogger(SecureProfileController.class);
    private static final String UPLOAD_DIR = "/var/www/uploads/profiles/";
    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("jpg", "jpeg", "png", "gif");
    private static final Set<String> ALLOWED_CONTENT_TYPES = Set.of(
        "image/jpeg", "image/png", "image/gif"
    );
    private static final long MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

    @PostMapping("/upload")
    public String uploadProfilePicture(
            @RequestParam("file") MultipartFile file,
            @RequestHeader("X-User-Id") String userId) throws IOException {

        // SECURITY: Validate file size
        if (file.getSize() > MAX_FILE_SIZE) {
            logger.warn("File size exceeded for user: {}", userId);
            throw new IllegalArgumentException("File too large");
        }

        // SECURITY: Validate content type from file headers (not just extension)
        String contentType = file.getContentType();
        if (contentType == null || !ALLOWED_CONTENT_TYPES.contains(contentType)) {
            logger.warn("Invalid content type {} from user: {}", contentType, userId);
            throw new IllegalArgumentException("Invalid file type");
        }

        // SECURITY: Extract and validate extension from original filename
        String originalFilename = file.getOriginalFilename();
        String extension = getFileExtension(originalFilename).toLowerCase();
        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            logger.warn("Invalid extension {} from user: {}", extension, userId);
            throw new IllegalArgumentException("Invalid file extension");
        }

        // SECURITY: Generate new filename - NEVER use user-provided filename
        String safeFilename = UUID.randomUUID().toString() + "." + extension;

        // SECURITY: Construct path and verify it's within upload directory
        Path uploadDir = Paths.get(UPLOAD_DIR).toAbsolutePath().normalize();
        Path targetPath = uploadDir.resolve(safeFilename).normalize();

        // SECURITY: Verify resolved path is still within upload directory
        if (!targetPath.startsWith(uploadDir)) {
            logger.error("Path traversal attempt by user: {}", userId);
            throw new SecurityException("Invalid file path");
        }

        Files.write(targetPath, file.getBytes());
        logger.info("File uploaded: {} by user: {}", safeFilename, userId);

        return "File uploaded successfully";
    }

    private String getFileExtension(String filename) {
        if (filename == null || !filename.contains(".")) {
            return "";
        }
        return filename.substring(filename.lastIndexOf(".") + 1);
    }
}
```

**Key Security Controls**:
- **UUID filename generation**: Completely ignores user-supplied filename, eliminating path traversal risk
- **Path canonicalization**: Uses `normalize()` and `startsWith()` to verify final path stays within upload directory
- **Content-type whitelist**: Only allows specific image types, validated from file headers
- **Extension whitelist**: Double-checks extension against allowed list
- **Size limits**: Prevents denial-of-service via large file uploads

Great questions! For multi-tenant file uploads with original filename preservation, you need a database mapping approach plus tenant isolation. This pattern is critical for SaaS applications.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import java.io.IOException;
import java.nio.file.*;
import java.security.MessageDigest;
import java.util.*;
import java.util.regex.Pattern;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.imageio.ImageIO;
import java.awt.image.BufferedImage;
import java.io.ByteArrayInputStream;

@RestController
@RequestMapping("/api/files")
public class SecureMultiTenantFileController {

    private static final Logger logger = LoggerFactory.getLogger(SecureMultiTenantFileController.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    // Configuration loaded from environment
    private final String baseUploadDir;
    private final FileMetadataRepository fileRepository;
    private final TenantService tenantService;
    private final VirusScannerService virusScanner;

    private static final Set<String> ALLOWED_EXTENSIONS = Set.of("jpg", "jpeg", "png", "gif", "pdf");
    private static final Map<String, List<byte[]>> FILE_SIGNATURES = Map.of(
        "jpg", List.of(new byte[]{(byte)0xFF, (byte)0xD8, (byte)0xFF}),
        "jpeg", List.of(new byte[]{(byte)0xFF, (byte)0xD8, (byte)0xFF}),
        "png", List.of(new byte[]{(byte)0x89, 0x50, 0x4E, 0x47}),
        "gif", List.of(new byte[]{0x47, 0x49, 0x46, 0x38}),
        "pdf", List.of(new byte[]{0x25, 0x50, 0x44, 0x46})
    );
    private static final long MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
    private static final Pattern SAFE_FILENAME_PATTERN = Pattern.compile("^[a-zA-Z0-9._-]+$");

    public SecureMultiTenantFileController(
            FileMetadataRepository fileRepository,
            TenantService tenantService,
            VirusScannerService virusScanner) {
        this.baseUploadDir = System.getenv("UPLOAD_BASE_DIR");
        if (this.baseUploadDir == null || this.baseUploadDir.isEmpty()) {
            throw new IllegalStateException("UPLOAD_BASE_DIR environment variable not set");
        }
        this.fileRepository = fileRepository;
        this.tenantService = tenantService;
        this.virusScanner = virusScanner;
    }

    @PostMapping("/upload")
    public ResponseEntity<FileUploadResponse> uploadFile(
            @RequestParam("file") MultipartFile file,
            @AuthenticationPrincipal UserPrincipal user) {

        String requestId = UUID.randomUUID().toString();
        String tenantId = user.getTenantId();
        String userId = user.getUserId();

        try {
            // LAYER 1: Basic validation
            validateBasicConstraints(file, requestId);

            // LAYER 2: Content validation (magic bytes)
            String extension = getAndValidateExtension(file.getOriginalFilename());
            validateFileSignature(file.getBytes(), extension, requestId);

            // LAYER 3: Deep content inspection for images
            if (isImageExtension(extension)) {
                validateImageContent(file.getBytes(), requestId);
            }

            // LAYER 4: Virus scan
            if (!virusScanner.scan(file.getBytes())) {
                auditLogger.error("requestId={} action=VIRUS_DETECTED tenant={} user={}", 
                    requestId, tenantId, userId);
                return ResponseEntity.badRequest().body(
                    new FileUploadResponse(false, "File rejected by security scan", null));
            }

            // LAYER 5: Generate secure storage path with tenant isolation
            Path tenantDir = getSecureTenantDirectory(tenantId);
            String storageFilename = generateSecureFilename(extension);
            Path targetPath = tenantDir.resolve(storageFilename);

            // LAYER 6: Final path validation
            validateFinalPath(targetPath, tenantDir, requestId, tenantId);

            // LAYER 7: Write file with restricted permissions
            Files.write(targetPath, file.getBytes(), 
                StandardOpenOption.CREATE_NEW,
                StandardOpenOption.WRITE);

            // Set restrictive file permissions (Unix)
            try {
                Set<PosixFilePermission> perms = Set.of(
                    PosixFilePermission.OWNER_READ,
                    PosixFilePermission.OWNER_WRITE
                );
                Files.setPosixFilePermissions(targetPath, perms);
            } catch (UnsupportedOperationException e) {
                // Windows - permissions handled differently
                logger.debug("POSIX permissions not supported");
            }

            // LAYER 8: Store metadata with sanitized original filename
            String sanitizedOriginalName = sanitizeDisplayFilename(file.getOriginalFilename());
            String fileHash = calculateSHA256(file.getBytes());

            FileMetadata metadata = new FileMetadata();
            metadata.setId(UUID.randomUUID().toString());
            metadata.setStorageFilename(storageFilename);
            metadata.setDisplayFilename(sanitizedOriginalName);
            metadata.setTenantId(tenantId);
            metadata.setUploadedBy(userId);
            metadata.setFileHash(fileHash);
            metadata.setFileSize(file.getSize());
            metadata.setContentType(extension);
            metadata.setUploadTimestamp(System.currentTimeMillis());

            fileRepository.save(metadata);

            auditLogger.info(
                "requestId={} action=FILE_UPLOADED tenant={} user={} fileId={} size={} hash={}",
                requestId, tenantId, userId, metadata.getId(), file.getSize(), fileHash);

            return ResponseEntity.ok(new FileUploadResponse(
                true, "File uploaded successfully", metadata.getId()));

        } catch (SecurityException e) {
            auditLogger.error("requestId={} action=SECURITY_VIOLATION tenant={} user={} error={}",
                requestId, tenantId, userId, e.getMessage());
            return ResponseEntity.status(403).body(
                new FileUploadResponse(false, "Security violation detected", null));
        } catch (IllegalArgumentException e) {
            logger.warn("requestId={} validation_error={}", requestId, e.getMessage());
            return ResponseEntity.badRequest().body(
                new FileUploadResponse(false, e.getMessage(), null));
        } catch (Exception e) {
            logger.error("requestId={} unexpected_error", requestId, e);
            return ResponseEntity.internalServerError().body(
                new FileUploadResponse(false, "Upload failed", null));
        }
    }

    @GetMapping("/download/{fileId}")
    public ResponseEntity<byte[]> downloadFile(
            @PathVariable String fileId,
            @AuthenticationPrincipal UserPrincipal user) throws IOException {

        // Authorization check: user can only access their tenant's files
        FileMetadata metadata = fileRepository.findById(fileId)
            .orElseThrow(() -> new IllegalArgumentException("File not found"));

        if (!metadata.getTenantId().equals(user.getTenantId())) {
            auditLogger.error("action=UNAUTHORIZED_ACCESS tenant={} user={} targetTenant={} fileId={}",
                user.getTenantId(), user.getUserId(), metadata.getTenantId(), fileId);
            throw new SecurityException("Access denied");
        }

        Path tenantDir = getSecureTenantDirectory(metadata.getTenantId());
        Path filePath = tenantDir.resolve(metadata.getStorageFilename()).normalize();

        // Re-verify path is within tenant directory
        if (!filePath.startsWith(tenantDir)) {
            throw new SecurityException("Invalid file path");
        }

        byte[] content = Files.readAllBytes(filePath);

        auditLogger.info("action=FILE_DOWNLOADED tenant={} user={} fileId={}",
            user.getTenantId(), user.getUserId(), fileId);

        return ResponseEntity.ok()
            .header("Content-Disposition", 
                "attachment; filename=\"" + metadata.getDisplayFilename() + "\"")
            .header("Content-Type", "application/octet-stream")
            .header("X-Content-Type-Options", "nosniff")
            .body(content);
    }

    private void validateBasicConstraints(MultipartFile file, String requestId) {
        if (file == null || file.isEmpty()) {
            throw new IllegalArgumentException("No file provided");
        }
        if (file.getSize() > MAX_FILE_SIZE) {
            logger.warn("requestId={} file_too_large size={}", requestId, file.getSize());
            throw new IllegalArgumentException("File exceeds maximum size");
        }
    }

    private String getAndValidateExtension(String filename) {
        if (filename == null || filename.isEmpty()) {
            throw new IllegalArgumentException("Invalid filename");
        }

        // Handle double extensions like "file.jpg.php"
        String[] parts = filename.split("\\.");
        if (parts.length < 2) {
            throw new IllegalArgumentException("File must have extension");
        }

        String extension = parts[parts.length - 1].toLowerCase();
        if (!ALLOWED_EXTENSIONS.contains(extension)) {
            throw new IllegalArgumentException("File type not allowed");
        }

        // Check for dangerous double extensions
        if (parts.length > 2) {
            String secondToLast = parts[parts.length - 2].toLowerCase();
            if (Set.of("php", "jsp", "asp", "aspx", "exe", "sh", "bat").contains(secondToLast)) {
                throw new SecurityException("Suspicious file extension pattern");
            }
        }

        return extension;
    }

    private void validateFileSignature(byte[] content, String extension, String requestId) {
        List<byte[]> validSignatures = FILE_SIGNATURES.get(extension);
        if (validSignatures == null) {
            return; // No signature check for this type
        }

        boolean validSignature = validSignatures.stream()
            .anyMatch(sig -> startsWith(content, sig));

        if (!validSignature) {
            logger.warn("requestId={} invalid_file_signature extension={}", requestId, extension);
            throw new SecurityException("File content does not match extension");
        }
    }

    private boolean startsWith(byte[] content, byte[] signature) {
        if (content.length < signature.length) return false;
        for (int i = 0; i < signature.length; i++) {
            if (content[i] != signature[i]) return false;
        }
        return true;
    }

    private void validateImageContent(byte[] content, String requestId) throws IOException {
        try {
            BufferedImage image = ImageIO.read(new ByteArrayInputStream(content));
            if (image == null) {
                throw new SecurityException("Invalid image content");
            }
            // Additional: could check for reasonable dimensions
            if (image.getWidth() > 10000 || image.getHeight() > 10000) {
                throw new IllegalArgumentException("Image dimensions too large");
            }
        } catch (IOException e) {
            logger.warn("requestId={} image_parse_failed", requestId);
            throw new SecurityException("Failed to validate image content");
        }
    }

    private boolean isImageExtension(String extension) {
        return Set.of("jpg", "jpeg", "png", "gif").contains(extension);
    }

    private Path getSecureTenantDirectory(String tenantId) throws IOException {
        // Validate tenant ID format to prevent path injection
        if (!tenantId.matches("^[a-zA-Z0-9-]{1,36}$")) {
            throw new SecurityException("Invalid tenant ID format");
        }

        Path baseDir = Paths.get(baseUploadDir).toAbsolutePath().normalize();
        Path tenantDir = baseDir.resolve(tenantId).normalize();

        // Verify tenant directory is within base directory
        if (!tenantDir.startsWith(baseDir)) {
            throw new SecurityException("Invalid tenant path");
        }

        // Create directory if it doesn't exist
        if (!Files.exists(tenantDir)) {
            Files.createDirectories(tenantDir);
        }

        return tenantDir;
    }

    private String generateSecureFilename(String extension) {
        return UUID.randomUUID().toString() + "." + extension;
    }

    private void validateFinalPath(Path targetPath, Path tenantDir, String requestId, String tenantId) {
        Path normalizedTarget = targetPath.toAbsolutePath().normalize();
        Path normalizedTenant = tenantDir.toAbsolutePath().normalize();

        if (!normalizedTarget.startsWith(normalizedTenant)) {
            logger.error("requestId={} path_traversal_attempt target={} allowed={}",
                requestId, normalizedTarget, normalizedTenant);
            throw new SecurityException("Path traversal detected");
        }
    }

    private String sanitizeDisplayFilename(String filename) {
        if (filename == null) return "unnamed";

        // Remove path components
        String name = Paths.get(filename).getFileName().toString();

        // Replace or remove dangerous characters
        name = name.replaceAll("[^a-zA-Z0-9._-]", "_");

        // Limit length
        if (name.length() > 255) {
            name = name.substring(0, 255);
        }

        return name.isEmpty() ? "unnamed" : name;
    }

    private String calculateSHA256(byte[] content) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(content);
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            String hex = Integer.toHexString(0xff & b);
            if (hex.length() == 1) hexString.append('0');
            hexString.append(hex);
        }
        return hexString.toString();
    }
}
