**Defense in Depth Layers**:

1. **Input Sanitization Layer**:
```php
// Strip path components from filename
$originalFilename = basename($file['name']);
// Remove control characters
$originalFilename = preg_replace('/[\x00-\x1F\x7F]/', '', $originalFilename);
```

2. **Path Resolution Layer**:
```php
// Always resolve paths and compare against allowed directory
$resolvedDir = realpath(dirname($fullPath));
$expectedDir = realpath($this->baseUploadPath . DIRECTORY_SEPARATOR . $config['subdir']);
if ($resolvedDir !== $expectedDir) {
    // Block the request - path traversal detected
}
```

3. **Content Verification Layer**:
```php
// Check MIME type from file content, not just extension
$finfo = new finfo(FILEINFO_MIME_TYPE);
$detectedMime = $finfo->file($file['tmp_name']);
// For images, additionally verify with getimagesize()
if (!@getimagesize($filepath)) {
    return false; // Not a valid image
}
```

4. **Server-Side Execution Prevention**:
```php
// .htaccess in upload directories
php_flag engine off
Options -ExecCGI
RemoveHandler .php .phtml .php3 .php4 .php5
```

**Additional Protections**:
- **Checksum verification**: SHA-256 hash stored on upload, verified on download to detect file tampering
- **Ownership verification**: Files are linked to user IDs, preventing unauthorized access
- **Audit logging**: All upload attempts logged with request IDs for forensic analysis
- **Restrictive permissions**: Files stored with 0640 permissions, directories with 0750
- **Separate storage**: Files stored outside web root when possible, served through PHP with proper headers
- **Rate limiting**: Implement at web server or application level to prevent abuse
- **Antivirus scanning**: In production, integrate ClamAV or similar for uploaded file scanning

File uploads are a common attack vector. The most critical vulnerability is path traversal, where attackers manipulate filenames to write files anywhere on the server.

**VULNERABLE CODE**:

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System.IO;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProfileController : ControllerBase
    {
        private readonly string _uploadPath = "wwwroot/uploads";

        [HttpPost("upload-picture")]
        public async Task<IActionResult> UploadPicture(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file uploaded");

            // VULNERABLE: Using user-supplied filename directly
            var filePath = Path.Combine(_uploadPath, file.FileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            return Ok(new { message = "File uploaded", path = filePath });
        }
    }
}
```

**Attack Payload**:
```text
Filename: ../../../wwwroot/webshell.aspx
Or: ....//....//....//etc/passwd
Or: ..\..\..\Windows\System32\config\SAM
```

**Why This Is Dangerous**:
- User-supplied `file.FileName` can contain `../` or `..\` sequences
- `Path.Combine()` does NOT sanitize path traversal characters
- Attacker can overwrite critical system files or web application files
- Writing a `.aspx` webshell gives remote code execution
- Can traverse to any directory the application has write access to

**SECURE VERSION**:

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System;
using System.IO;
using System.Linq;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProfileController : ControllerBase
    {
        private readonly string _uploadPath;
        private readonly ILogger<ProfileController> _logger;
        private static readonly string[] AllowedExtensions = { ".jpg", ".jpeg", ".png", ".gif" };
        private const long MaxFileSize = 5 * 1024 * 1024; // 5MB

        public ProfileController(ILogger<ProfileController> logger)
        {
            _logger = logger;
            _uploadPath = Path.GetFullPath("wwwroot/uploads");
        }

        [HttpPost("upload-picture")]
        public async Task<IActionResult> UploadPicture(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file uploaded");

            if (file.Length > MaxFileSize)
                return BadRequest("File exceeds maximum size of 5MB");

            // SECURE: Extract only the filename, removing any path information
            var originalFileName = Path.GetFileName(file.FileName);

            // SECURE: Validate file extension
            var extension = Path.GetExtension(originalFileName).ToLowerInvariant();
            if (!AllowedExtensions.Contains(extension))
            {
                _logger.LogWarning("Blocked upload attempt with extension: {Extension}", extension);
                return BadRequest("Only image files are allowed");
            }

            // SECURE: Generate unique filename to prevent overwrites
            var safeFileName = $"{Guid.NewGuid()}{extension}";
            var fullPath = Path.Combine(_uploadPath, safeFileName);

            // SECURE: Verify the resolved path is within the upload directory
            var resolvedPath = Path.GetFullPath(fullPath);
            if (!resolvedPath.StartsWith(_uploadPath, StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning("Path traversal attempt detected: {OriginalName}", originalFileName);
                return BadRequest("Invalid file path");
            }

            using (var stream = new FileStream(resolvedPath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            _logger.LogInformation("File uploaded: {SafeName} (original: {OriginalName})", 
                safeFileName, originalFileName);

            return Ok(new { fileName = safeFileName });
        }
    }
}
```

**Key Security Controls**:
- **Path.GetFileName()**: Strips directory path components from user input
- **Extension allowlist**: Only permits specific safe file extensions
- **Generated filename**: Uses GUID to prevent filename-based attacks
- **Path canonicalization check**: Verifies resolved path stays within upload directory
- **File size limit**: Prevents denial of service via large uploads

Excellent questions! Allowing subdirectories requires careful validation, and content verification is essential since attackers can embed malicious content in files with valid extensions.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using System;
using System.IO;
using System.Linq;
using System.Text.RegularExpressions;
using SixLabors.ImageSharp;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.RateLimiting;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class FileUploadController : ControllerBase
    {
        private readonly IFileUploadService _uploadService;
        private readonly ILogger<FileUploadController> _logger;
        private readonly IAuditLogger _auditLogger;

        public FileUploadController(
            IFileUploadService uploadService,
            ILogger<FileUploadController> logger,
            IAuditLogger auditLogger)
        {
            _uploadService = uploadService;
            _logger = logger;
            _auditLogger = auditLogger;
        }

        [HttpPost("upload")]
        [EnableRateLimiting("FileUploadPolicy")]
        [RequestSizeLimit(10 * 1024 * 1024)] // 10MB max
        public async Task<IActionResult> UploadFile(
            IFormFile file, 
            [FromQuery] string? subdirectory = null)
        {
            var userId = User.FindFirst("sub")?.Value;

            try
            {
                var result = await _uploadService.ProcessUploadAsync(
                    file, subdirectory, userId);

                await _auditLogger.LogAsync(
                    "FileUpload", 
                    userId, 
                    $"Uploaded: {result.FileName}");

                return Ok(result);
            }
            catch (InvalidFileException ex)
            {
                _logger.LogWarning(ex, 
                    "Invalid file upload attempt by user {UserId}", userId);
                return BadRequest(ex.Message);
            }
            catch (SecurityException ex)
            {
                await _auditLogger.LogSecurityEventAsync(
                    "PathTraversalAttempt", userId, ex.Message);
                return BadRequest("Invalid file path");
            }
        }
    }

    public class FileUploadService : IFileUploadService
    {
        private readonly string _baseUploadPath;
        private readonly ILogger<FileUploadService> _logger;
        private readonly IVirusScanService _virusScanner;

        private static readonly Dictionary<string, byte[][]> MagicBytes = new()
        {
            { ".jpg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".jpeg", new[] { new byte[] { 0xFF, 0xD8, 0xFF } } },
            { ".png", new[] { new byte[] { 0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A } } },
            { ".gif", new[] { new byte[] { 0x47, 0x49, 0x46, 0x38, 0x37, 0x61 }, 
                            new byte[] { 0x47, 0x49, 0x46, 0x38, 0x39, 0x61 } } }
        };

        private static readonly Regex SafeSubdirectoryPattern = 
            new(@"^[a-zA-Z0-9_-]+$", RegexOptions.Compiled);

        public FileUploadService(
            IConfiguration config, 
            ILogger<FileUploadService> logger,
            IVirusScanService virusScanner)
        {
            _baseUploadPath = Path.GetFullPath(
                config["FileUpload:BasePath"] ?? "uploads");
            _logger = logger;
            _virusScanner = virusScanner;

            // Ensure upload directory exists
            Directory.CreateDirectory(_baseUploadPath);
        }

        public async Task<UploadResult> ProcessUploadAsync(
            IFormFile file, string? subdirectory, string userId)
        {
            // LAYER 1: Validate subdirectory name if provided
            var targetPath = _baseUploadPath;
            if (!string.IsNullOrEmpty(subdirectory))
            {
                targetPath = ValidateAndBuildSubdirectoryPath(subdirectory);
            }

            // LAYER 2: Validate and sanitize filename
            var originalName = Path.GetFileName(file.FileName);
            var extension = Path.GetExtension(originalName).ToLowerInvariant();

            if (!MagicBytes.ContainsKey(extension))
                throw new InvalidFileException("File type not allowed");

            // LAYER 3: Validate file content matches extension
            await ValidateFileContentAsync(file, extension);

            // LAYER 4: Generate safe filename with user context
            var safeFileName = $"{userId}_{DateTimeOffset.UtcNow.ToUnixTimeSeconds()}_{Guid.NewGuid():N}{extension}";
            var fullPath = Path.Combine(targetPath, safeFileName);

            // LAYER 5: Final path traversal check
            var resolvedPath = Path.GetFullPath(fullPath);
            if (!resolvedPath.StartsWith(_baseUploadPath, StringComparison.OrdinalIgnoreCase))
            {
                throw new SecurityException(
                    $"Path traversal detected: attempted to write to {resolvedPath}");
            }

            // LAYER 6: Virus scan before saving
            using var memoryStream = new MemoryStream();
            await file.CopyToAsync(memoryStream);
            memoryStream.Position = 0;

            var scanResult = await _virusScanner.ScanAsync(memoryStream);
            if (!scanResult.IsClean)
            {
                throw new InvalidFileException("File failed security scan");
            }

            // LAYER 7: Reprocess image to strip metadata/embedded content
            memoryStream.Position = 0;
            using var image = await Image.LoadAsync(memoryStream);

            Directory.CreateDirectory(targetPath);
            await image.SaveAsync(resolvedPath);

            return new UploadResult
            {
                FileName = safeFileName,
                RelativePath = Path.GetRelativePath(_baseUploadPath, resolvedPath)
            };
        }

        private string ValidateAndBuildSubdirectoryPath(string subdirectory)
        {
            // Only allow single-level, alphanumeric subdirectories
            if (!SafeSubdirectoryPattern.IsMatch(subdirectory))
            {
                throw new InvalidFileException(
                    "Subdirectory name contains invalid characters");
            }

            if (subdirectory.Length > 50)
            {
                throw new InvalidFileException(
                    "Subdirectory name too long");
            }

            var subPath = Path.Combine(_baseUploadPath, subdirectory);
            var resolved = Path.GetFullPath(subPath);

            if (!resolved.StartsWith(_baseUploadPath, StringComparison.OrdinalIgnoreCase))
            {
                throw new SecurityException("Invalid subdirectory path");
            }

            return resolved;
