            var bytesRead = await stream.ReadAsync(buffer, 0, buffer.Length);

            var isValidSignature = expectedSignatures.Any(signature =>
                bytesRead >= signature.Length &&
                buffer.Take(signature.Length).SequenceEqual(signature));

            if (!isValidSignature)
