            if (!ALLOWED_MIME_TYPES.contains(detectedMimeType)) {
                securityViolationCounter.increment();
                securityLogger.warn("requestId={} action=UPLOAD_DENIED reason=INVALID_MIME " +
                    "userId={} filename={} detectedMime={}", 
                    requestId, user.getId(), originalFileName, detectedMimeType);
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid file content");
                return;
            }

            // Layer 7: Malware scanning (integration point)
            if (!scanForMalware(fileContent, requestId)) {
                securityViolationCounter.increment();
                securityLogger.error("requestId={} action=UPLOAD_DENIED reason=MALWARE_DETECTED " +
                    "userId={}", requestId, user.getId());
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "File rejected");
                return;
            }

            // Layer 8: Generate secure storage key (no user input in path)
            String fileHash = computeSHA256(fileContent);
            String storageKey = String.format("uploads/%s/%s/%s%s",
                user.getId(),
                Instant.now().toString().substring(0, 10), // Date partition
                fileHash,
                extension
            );

            // Layer 9: Upload to S3 with security metadata
            PutObjectRequest putRequest = PutObjectRequest.builder()
                .bucket(S3_BUCKET)
                .key(storageKey)
                .contentType(detectedMimeType)
                .contentDisposition("attachment") // Prevent browser execution
                .metadata(Map.of(
                    "original-filename", originalFileName,
                    "uploader-id", user.getId(),
                    "upload-timestamp", Instant.now().toString(),
                    "request-id", requestId,
                    "content-hash", fileHash
                ))
                .serverSideEncryption(ServerSideEncryption.AES256)
                .build();

            s3Client.putObject(putRequest, RequestBody.fromBytes(fileContent));

            // Layer 10: Store metadata in database (original filename preserved here)
            String fileId = UUID.randomUUID().toString();
            storeFileMetadata(fileId, user.getId(), originalFileName, storageKey, 
                              fileContent.length, detectedMimeType, fileHash);

            // Success logging and metrics
            uploadSuccessCounter.increment();
            long duration = System.currentTimeMillis() - startTime;
            logger.info("requestId={} action=UPLOAD_SUCCESS userId={} fileId={} size={} duration={}ms",
                requestId, user.getId(), fileId, fileContent.length, duration);

            // Return file ID, not storage path
            response.setContentType("application/json");
            response.getWriter().write(String.format(
                "{\"success\":true,\"fileId\":\"%s\",\"displayName\":\"%s\"}",
                fileId, originalFileName
            ));

        } catch (Exception e) {
            uploadFailureCounter.increment();
            logger.error("requestId={} action=UPLOAD_ERROR error={}", requestId, e.getMessage(), e);
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Upload failed");
        }
    }

    private String sanitizeDisplayFilename(String filename) {
        if (filename == null) return "unnamed";
        // Remove path separators and null bytes
        return filename.replaceAll("[/\\\\\\x00]", "_")
                       .replaceAll("\\.\\.", "_")
                       .substring(0, Math.min(filename.length(), 255));
    }

    private String extractAndValidateExtension(String filename) {
        int lastDot = filename.lastIndexOf('.');
        if (lastDot < 0 || lastDot == filename.length() - 1) return null;
        String ext = filename.substring(lastDot).toLowerCase();
        return ALLOWED_EXTENSIONS.contains(ext) ? ext : null;
    }

    private String computeSHA256(byte[] content) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(content);
        StringBuilder hexString = new StringBuilder();
        for (byte b : hash) {
            hexString.append(String.format("%02x", b));
        }
        return hexString.toString();
    }

