3. **Serving Files Securely**:
```java
@GetMapping("/api/v1/files/{fileId}")
public ResponseEntity<Resource> downloadFile(@PathVariable String fileId, 
                                              @AuthenticationPrincipal User user) {
    FileMetadata meta = fileRepository.findById(fileId)
        .orElseThrow(() -> new NotFoundException("File not found"));

    // Authorization: User can only download their own files
    if (!meta.getUserId().equals(user.getId())) {
        throw new ForbiddenException("Access denied");
    }

    // Generate presigned URL (time-limited, no path exposure)
    GetObjectPresignRequest presignRequest = GetObjectPresignRequest.builder()
        .signatureDuration(Duration.ofMinutes(5))
        .getObjectRequest(GetObjectRequest.builder()
            .bucket(S3_BUCKET)
            .key(meta.getStorageKey())
            .responseContentDisposition("attachment; filename=\"" + 
                meta.getOriginalFilename() + "\"")
            .build())
        .build();

    URL presignedUrl = s3Presigner.presignGetObject(presignRequest).url();
    return ResponseEntity.status(HttpStatus.FOUND)
        .location(URI.create(presignedUrl.toString()))
        .build();
}
